// Получаем текст из поля Tasks
const fullText = $input.first().json.candidates[0].content.parts[0].text;

// Проверяем, что данные получены
if (!fullText) {
  console.log('Поле Tasks не найдено или пустое');
  return [];
}

// Разделяем по разделителю ---
const tasks = fullText.split('---').map(task => task.trim()).filter(task => task.length > 0);

console.log(`Найдено задач: ${tasks.length}`);

// Создаем отдельные элементы для каждого ТЗ
const result = tasks.map((task) => {
  return {
    task_content: task
  };
});

return result;

